head.b:skin:
:root {
  --bg: #f3f6fb;
  --surface: #ffffff;
  --text: #1c2634;
  --muted: #6b778c;
  --nav-dark: #263647;
  --top-dark: #1e2a37;
  --hero-dark: #1b2740;
  --hero-accent: #2f3d56;
  --primary: #2f6fed;
  --primary-hover: #1f56c4;
  --danger: #d83a52;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: 'Cairo', Arial, sans-serif;
  background: var(--bg);
  color: var(--text);
  line-height: 1.6;
}

a {
  text-decoration: none;
  color: inherit;
}

.container {
  width: min(1160px, 92%);
  margin: 0 auto;
}

.top-strip {
  background: var(--top-dark);
  color: #cfdae7;
  font-size: 0.88rem;
}

.top-strip-inner {
  min-height: 42px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
}

.top-contact {
  display: flex;
  align-items: center;
  gap: 18px;
}

.top-contact a,
.top-social a {
  display: inline-flex;
  align-items: center;
  gap: 6px;
}

.top-social {
  display: inline-flex;
  gap: 14px;
}

.site-header {
  background: var(--nav-dark);
  color: #ffffff;
  border-bottom: 1px solid rgba(255, 255, 255, 0.08);
  position: relative;
}

.nav-bar {
  min-height: 84px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 24px;
}

.logo-wrap {
  min-width: 180px;
}

#header {
  width: 100%;
}

#header .widget,
#header .widget-content {
  text-align: left;
}

#header img {
  max-width: 210px;
  width: auto;
  height: auto;
}

#header h1,
#header h2,
#header .title {
  margin: 0;
  color: #ffffff;
  font-size: 1.3rem;
  font-weight: 800;
}

.primary-nav {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: flex-end;
  gap: 10px;
}

.primary-nav a {
  color: #ffffff;
  font-size: 0.9rem;
  font-weight: 700;
  letter-spacing: 0.02em;
  text-transform: uppercase;
  padding: 10px 12px;
  border-radius: 8px;
  transition: background-color 0.2s ease;
}

.primary-nav a:hover {
  background: rgba(255, 255, 255, 0.12);
}

.primary-nav .contact-btn {
  background: var(--primary);
  text-transform: none;
  border-radius: 8px;
  padding: 10px 16px;
}

.primary-nav .contact-btn:hover {
  background: var(--primary-hover);
}

.lang-toggle {
  background: transparent;
  border: 1.5px solid rgba(255, 255, 255, 0.5);
  color: #ffffff;
  border-radius: 8px;
  padding: 6px 14px;
  font-family: inherit;
  font-size: 0.88rem;
  font-weight: 700;
  cursor: pointer;
  transition: background-color 0.2s ease;
  white-space: nowrap;
}

.lang-toggle:hover {
  background: rgba(255, 255, 255, 0.12);
}

.hamburger {
  display: none;
  background: transparent;
  border: none;
  color: #ffffff;
  font-size: 1.5rem;
  cursor: pointer;
  padding: 8px;
  border-radius: 8px;
  align-items: center;
  justify-content: center;
  line-height: 1;
}

.hamburger:hover {
  background: rgba(255, 255, 255, 0.12);
}

.mobile-menu {
  display: none;
  flex-direction: column;
  position: absolute;
  top: 100%;
  left: 0;
  right: 0;
  background: var(--nav-dark);
  z-index: 200;
  border-top: 1px solid rgba(255, 255, 255, 0.08);
  padding: 4px 0 8px;
}

.mobile-menu.open {
  display: flex;
}

.mobile-menu .container {
  display: flex;
  flex-direction: column;
}

.mobile-menu a {
  color: #ffffff;
  padding: 12px 16px;
  font-size: 0.95rem;
  font-weight: 700;
  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
}

.mobile-menu a:hover {
  background: rgba(255, 255, 255, 0.08);
}

.download-btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  margin-top: 16px;
  padding: 10px 24px;
  background: var(--primary);
  color: #ffffff;
  border: none;
  border-radius: 10px;
  font-family: inherit;
  font-size: 0.96rem;
  font-weight: 700;
  cursor: pointer;
  text-decoration: none;
  transition: background-color 0.2s ease;
}

.download-btn:hover {
  background: var(--primary-hover);
}

.hero {
  position: relative;
  background: linear-gradient(150deg, var(--hero-dark) 0%, #202e4a 55%, var(--hero-accent) 100%);
  color: #ffffff;
  padding: 80px 0 96px;
  overflow: hidden;
}

.hero::before {
  content: '';
  position: absolute;
  inset: 0;
  background: radial-gradient(circle at 20% 30%, rgba(255, 255, 255, 0.08) 0, transparent 42%),
    radial-gradient(circle at 80% 70%, rgba(255, 255, 255, 0.05) 0, transparent 36%);
  pointer-events: none;
}

.hero-inner {
  position: relative;
  z-index: 1;
  text-align: center;
}

.hero h1 {
  margin: 0;
  font-size: clamp(1.8rem, 3.4vw, 2.9rem);
  font-weight: 800;
  letter-spacing: 0.02em;
  text-transform: uppercase;
}

.hero p {
  margin: 14px auto 0;
  max-width: 860px;
  color: rgba(255, 255, 255, 0.9);
}

.search-wrap {
  margin: 38px auto 0;
  max-width: 860px;
}

.search-card {
  background: var(--surface);
  border-radius: 14px;
  box-shadow: 0 18px 45px rgba(10, 23, 44, 0.3);
  padding: 26px;
}

.search-form {
  display: flex;
  gap: 12px;
}

.search-form input[name='q'] {
  flex: 1;
  min-height: 58px;
  border: 1px solid #d4dce8;
  border-radius: 10px;
  padding: 0 16px;
  font-size: 1rem;
  font-family: inherit;
  outline: none;
  background: #ffffff;
  transition: border-color 0.2s ease, box-shadow 0.2s ease;
}

.search-form input[name='q']:focus {
  border-color: var(--primary);
  box-shadow: 0 0 0 3px rgba(47, 111, 237, 0.16);
}

.search-form button {
  min-height: 58px;
  border: 0;
  border-radius: 10px;
  padding: 0 24px;
  font-family: inherit;
  font-size: 1rem;
  font-weight: 700;
  color: #ffffff;
  background: var(--primary);
  cursor: pointer;
  transition: background-color 0.2s ease;
}

.search-form button:hover {
  background: var(--primary-hover);
}

.content-section {
  padding: 48px 0 78px;
}

.empty-state,
.result-card {
  background: var(--surface);
  border: 1px solid #e2e8f2;
  border-radius: 14px;
  box-shadow: 0 8px 24px rgba(18, 32, 54, 0.08);
  padding: 24px;
}

.result-card + .result-card {
  margin-top: 18px;
}

.result-title {
  margin: 0 0 14px;
  text-align: center;
  color: #22344d;
  font-size: 1.4rem;
  font-weight: 800;
  word-break: break-word;
}

.result-body {
  text-align: center;
}

.result-body img {
  max-width: 100%;
  height: auto;
  border-radius: 10px;
  border: 1px solid #d7dfeb;
}

.not-found {
  margin: 0;
  text-align: center;
  color: var(--danger);
  font-size: 1.05rem;
  font-weight: 700;
}

.hint {
  margin: 0;
  text-align: center;
  color: var(--muted);
}

.site-footer {
  background: #111a2b;
  color: #ced8e6;
  padding: 42px 0;
}

.footer-inner {
  display: grid;
  grid-template-columns: 1.3fr 1fr 1fr;
  gap: 26px;
}

.footer-brand {
  font-size: 1.02rem;
  font-weight: 700;
}

.footer-meta {
  color: #aebace;
  font-size: 0.94rem;
}

.footer-title {
  margin: 0 0 10px;
  font-size: 1.02rem;
  color: #ffffff;
}

.footer-links,
.footer-contact {
  display: flex;
  flex-direction: column;
  gap: 8px;
  font-size: 0.94rem;
}

.footer-links a:hover,
.footer-contact a:hover,
.social-links a:hover {
  color: #ffffff;
}

.social-links {
  display: inline-flex;
  gap: 12px;
  margin-top: 12px;
}

@media (max-width: 980px) {
  .primary-nav {
    justify-content: flex-start;
  }

  .footer-inner {
    grid-template-columns: 1fr 1fr;
  }
}

@media (max-width: 768px) {
  .top-contact {
    display: none;
  }

  .top-strip-inner {
    flex-direction: row;
    justify-content: center;
    padding: 8px 0;
  }

  .nav-bar {
    flex-direction: row;
    justify-content: space-between;
    align-items: center;
    min-height: 60px;
    padding: 10px 0;
  }

  #header img {
    max-width: 130px;
  }

  .primary-nav {
    display: none;
  }

  .lang-toggle {
    font-size: 0.8rem;
    padding: 5px 10px;
  }

  .hamburger {
    display: flex;
  }

  .search-form {
    flex-direction: column;
  }

  .footer-inner {
    grid-template-columns: 1fr;
  }
}

body.script:
//
  // ── Hamburger / mobile menu ──
  function toggleMenu() {
    document.getElementById('mobile-menu').classList.toggle('open');
  }
  document.addEventListener('DOMContentLoaded', function () {
    document.querySelectorAll('#mobile-menu a').forEach(function (link) {
      link.addEventListener('click', function () {
        document.getElementById('mobile-menu').classList.remove('open');
      });
    });
  });

  // ── Download certificate ──
  function downloadCert(btn) {
    const card = btn.closest('.result-card');
    const img = card ? card.querySelector('.result-body img') : null;
    if (!img) {
      alert(currentLang === 'ar' ? '\u0644\u0645 \u064a\u062a\u0645 \u0627\u0644\u0639\u062b\u0648\u0631 \u0639\u0644\u0649 \u0635\u0648\u0631\u0629 \u0627\u0644\u0634\u0647\u0627\u062f\u0629.' : 'No certificate image found.');
      return;
    }
    const titleEl = card.querySelector('.result-title');
    const filename = (titleEl ? titleEl.textContent.trim().replace(/\s+/g, '_') : 'certificate') + '.jpg';
    const a = document.createElement('a');
    a.href = img.src;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  }

  // ── Language toggle EN / AR ──
  var langTexts = {
    en: {
      verifyLink: 'Verify Certificate',
      contactBtn: 'Contact Us',
      heroTitle: 'Student Certificate Verification',
      heroDesc: 'Enter your certificate ID to instantly verify and view official certificate details.',
      searchPlaceholder: 'Enter Your Student ID',
      verifyBtnText: 'Verify',
      downloadBtn: 'Download Certificate',
      langLabel: 'AR'
    },
    ar: {
      verifyLink: '\u0627\u0644\u062a\u062d\u0642\u0642 \u0645\u0646 \u0627\u0644\u0634\u0647\u0627\u062f\u0629',
      contactBtn: '\u0627\u062a\u0635\u0644 \u0628\u0646\u0627',
      heroTitle: '\u0627\u0644\u062a\u062d\u0642\u0642 \u0645\u0646 \u0634\u0647\u0627\u062f\u0629 \u0627\u0644\u0637\u0627\u0644\u0628',
      heroDesc: '\u0623\u062f\u062e\u0644 \u0631\u0642\u0645 \u0627\u0644\u0634\u0647\u0627\u062f\u0629 \u0644\u0644\u062a\u062d\u0642\u0642 \u0627\u0644\u0641\u0648\u0631\u064a \u0648\u0639\u0631\u0636 \u062a\u0641\u0627\u0635\u064a\u0644 \u0627\u0644\u0634\u0647\u0627\u062f\u0629 \u0627\u0644\u0631\u0633\u0645\u064a\u0629.',
      searchPlaceholder: '\u0623\u062f\u062e\u0644 \u0631\u0642\u0645 \u0627\u0644\u0637\u0627\u0644\u0628',
      verifyBtnText: '\u062a\u062d\u0642\u0642',
      downloadBtn: '\u062a\u062d\u0645\u064a\u0644 \u0627\u0644\u0634\u0647\u0627\u062f\u0629',
      langLabel: 'EN'
    }
  };
  let currentLang = 'en';

  function toggleLang() {
    currentLang = currentLang === 'en' ? 'ar' : 'en';
    var t = langTexts[currentLang];
    document.documentElement.setAttribute('dir', currentLang === 'ar' ? 'rtl' : 'ltr');
    document.getElementById('lang-toggle').textContent = t.langLabel;
    document.querySelectorAll('[data-i18n="verifyLink"]').forEach(function (el) { el.textContent = t.verifyLink; });
    document.querySelectorAll('[data-i18n="contactBtn"]').forEach(function (el) { el.textContent = t.contactBtn; });
    var heroTitle = document.querySelector('.hero h1');
    if (heroTitle) heroTitle.textContent = t.heroTitle;
    var heroDesc = document.querySelector('.hero p');
    if (heroDesc) heroDesc.textContent = t.heroDesc;
    var searchInput = document.querySelector('.search-form input[name="q"]');
    if (searchInput) searchInput.setAttribute('placeholder', t.searchPlaceholder);
    var verifyBtn = document.querySelector('.search-form button');
    if (verifyBtn) verifyBtn.innerHTML = '<i class="fa-solid fa-magnifying-glass"></i> ' + t.verifyBtnText;
    document.querySelectorAll('[data-i18n="downloadBtn"]').forEach(function (el) { el.textContent = t.downloadBtn; });
  }
//
